public async Task<bool> PurchaseTicketsAsync(int eventId, int quantity)
{
    using (var context = new EventBookingContext())
    {
        using (var transaction = await context.Database.BeginTransactionAsync())
        {
            try
            {
                // Check available seats
                var eventDetails = await context.Events
                    .Where(e => e.Id == eventId)
                    .Include(e => e.Seats)
                    .SingleOrDefaultAsync();

                if (eventDetails == null || eventDetails.AvailableSeats < quantity)
                {
                    return false; // Not enough available seats
                }

                // Validate purchase quantity
                if (quantity <= 0)
                {
                    return false; // Invalid purchase quantity
                }

                // Update inventory
                eventDetails.AvailableSeats -= quantity;

                await context.SaveChangesAsync();
                await transaction.CommitAsync();

                return true; // Purchase successful
            }
            catch (DbUpdateConcurrencyException)
            {
                // Handle concurrency conflict
                await transaction.RollbackAsync();
                return false; // Retry the purchase
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
                throw; // Re-throw unexpected exceptions
            }
        }
    }
}